<h4 class="text-muted mb-4">@WarehouseState.Warehouses[WarehouseState.SelectedWarehouseId]</h4>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card border-danger">
            <div class="card-body text-center">
                <h5 class="card-title">
                    <span class="text-danger">⚠</span> Low Stock Alerts
                </h5>
                <p class="display-4 fw-bold text-danger">
                    @if (_loading)
                    {
                        <span class="spinner-border"></span>
                    }
                    else
                    {
                        @WarehouseState.LowStockAlertCount
                    }
                </p>
                <p class="text-muted mb-0">Items below minimum levels</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="mb-1">
                    <span class="badge bg-success">Active</span>
                </p>
                <p class="text-muted mb-0">Refreshing every 10 seconds</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Selected Site</h5>
                <p class="fs-5 fw-semibold mb-1">@WarehouseState.SelectedWarehouseId</p>
                <p class="text-muted mb-0">@WarehouseState.Warehouses[WarehouseState.SelectedWarehouseId]</p>
            </div>
        </div>
    </div>
</div>

@if (_lastRefreshed.HasValue)
{
    <p class="text-muted mt-3">
        <small>Last refreshed: @_lastRefreshed.Value.ToString("HH:mm:ss")</small>
    </p>
}

@code {
    private CancellationTokenSource? _cts;
    private bool _loading = true;
    private DateTime? _lastRefreshed;

    protected override void OnInitialized()
    {
        WarehouseState.OnWarehouseChanged += HandleWarehouseChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await RunPollingLoopAsync();
        }
    }

    private void HandleWarehouseChanged()
    {
        // Cancel current polling and restart for the new warehouse.
        _cts?.Cancel();
        _ = InvokeAsync(async () =>
        {
            _loading = true;
            StateHasChanged();
            await RunPollingLoopAsync();
        });
    }

    private async Task RunPollingLoopAsync()
    {
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        try
        {
            while (!token.IsCancellationRequested)
            {
                var count = await AlertService.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);
                if (token.IsCancellationRequested) break;

                WarehouseState.SetAlertCount(count);
                _loading = false;
                _lastRefreshed = DateTime.Now;
                StateHasChanged();

                await Task.Delay(TimeSpan.FromSeconds(10), token);
            }
        }
        catch (OperationCanceledException) { }
    }

    public void Dispose()
    {
        WarehouseState.OnWarehouseChanged -= HandleWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

